type AccountBalance struct {
	AvailableBalance float64
	PendingBalance   float64
	Currency         string
	LastUpdated      int64
}

type TransactionRecord struct {
	TransactionID string
	FromAccountID string
	ToAccountID   string
	Amount        float64
	Currency      string
	Type          pb.TransactionType
	Status        pb.TransactionStatus
	Description   string
	CreatedAt     int64
}

type TransactionServer struct {
	pb.UnimplementedTransactionServiceServer
	mu              sync.RWMutex
	balances        map[string]*AccountBalance
	transactions    map[string]*TransactionRecord
	idempotencyKeys map[string]string // idempotency_key -> transaction_id
}

func NewTransactionServer() *TransactionServer {
	s := &TransactionServer{
		balances:        make(map[string]*AccountBalance),
		transactions:    make(map[string]*TransactionRecord),
		idempotencyKeys: make(map[string]string),
	}

	// Seed some test accounts
	s.balances["ACC-001"] = &AccountBalance{
		AvailableBalance: 10000.00,
		PendingBalance:   0,
		Currency:         "USD",
		LastUpdated:      time.Now().Unix(),
	}
	s.balances["ACC-002"] = &AccountBalance{
		AvailableBalance: 5000.00,
		PendingBalance:   0,
		Currency:         "USD",
		LastUpdated:      time.Now().Unix(),
	}
	s.balances["ACC-003"] = &AccountBalance{
		AvailableBalance: 25000.00,
		PendingBalance:   0,
		Currency:         "USD",
		LastUpdated:      time.Now().Unix(),
	}

	return s
}

func (s *TransactionServer) CreateTransaction(ctx context.Context, req *pb.CreateTransactionRequest) (*pb.CreateTransactionResponse, error) {
	// Extract metadata for tracing/logging
	md, ok := metadata.FromIncomingContext(ctx)
	if ok {
		if requestIDs := md.Get("x-request-id"); len(requestIDs) > 0 {
			log.Printf("Processing request with x-request-id: %s", requestIDs[0])
		}
	}

	// Validate request
	if err := validateCreateTransactionRequest(req); err != nil {
		return nil, err
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	// Idempotency check
	if req.IdempotencyKey != "" {
		if existingTxID, exists := s.idempotencyKeys[req.IdempotencyKey]; exists {
			existingTx := s.transactions[existingTxID]
			return &pb.CreateTransactionResponse{
				TransactionId: existingTx.TransactionID,
				Status:        existingTx.Status,
				Message:       "Duplicate request - returning existing transaction",
				CreatedAt:     existingTx.CreatedAt,
			}, nil
		}
	}

	now := time.Now()
	txID := fmt.Sprintf("TXN-%d", now.UnixNano())

	switch req.Type {
	case pb.TransactionType_TRANSACTION_TYPE_TRANSFER:
		return s.processTransfer(req, txID, now)
	case pb.TransactionType_TRANSACTION_TYPE_DEPOSIT:
		return s.processDeposit(req, txID, now)
	case pb.TransactionType_TRANSACTION_TYPE_WITHDRAWAL:
		return s.processWithdrawal(req, txID, now)
	default:
		return nil, status.Errorf(codes.InvalidArgument, "unsupported transaction type: %v", req.Type)
	}
}

func (s *TransactionServer) processTransfer(req *pb.CreateTransactionRequest, txID string, now time.Time) (*pb.CreateTransactionResponse, error) {
	fromBalance, fromExists := s.balances[req.FromAccountId]
	if !fromExists {
		return nil, status.Errorf(codes.NotFound, "source account %s not found", req.FromAccountId)
	}

	toBalance, toExists := s.balances[req.ToAccountId]
	if !toExists {
		return nil, status.Errorf(codes.NotFound, "destination account %s not found", req.ToAccountId)
	}

	if fromBalance.AvailableBalance < req.Amount {
		txRecord := s.createTransactionRecord(txID, req, pb.TransactionStatus_TRANSACTION_STATUS_FAILED, now)
		s.transactions[txID] = txRecord
		return &pb.CreateTransactionResponse{
			TransactionId: txID,
			Status:        pb.TransactionStatus_TRANSACTION_STATUS_FAILED,
			Message:       "Insufficient funds",
			CreatedAt:     now.Unix(),
		}, nil
	}

	// Process the transfer
	fromBalance.AvailableBalance -= req.Amount
	fromBalance.LastUpdated = now.Unix()
	toBalance.AvailableBalance += req.Amount
	toBalance.LastUpdated = now.Unix()

	txRecord := s.createTransactionRecord(txID, req, pb.TransactionStatus_TRANSACTION_STATUS_COMPLETED, now)
	s.transactions[txID] = txRecord

	if req.IdempotencyKey != "" {
		s.idempotencyKeys[req.IdempotencyKey] = txID
	}

	log.Printf("Transfer completed: %s -> %s, amount: %.2f %s, txID: %s",
		req.FromAccountId, req.ToAccountId, req.Amount, req.Currency, txID)

	return &pb.CreateTransactionResponse{
		TransactionId: txID,
		Status:        pb.TransactionStatus_TRANSACTION_STATUS_COMPLETED,
		Message:       "Transfer completed successfully",
		CreatedAt:     now.Unix(),
	}, nil
}

func (s *TransactionServer) processDeposit(req *pb.CreateTransactionRequest, txID string, now time.Time) (*pb.CreateTransactionResponse, error) {
	toBalance, toExists := s.balances[req.ToAccountId]
	if !toExists {
		// Auto-create account on deposit
		s.balances[req.ToAccountId] = &AccountBalance{
			AvailableBalance: 0,
			PendingBalance:   0,
			Currency:         req.Currency,
			LastUpdated:      now.Unix(),
		}
		toBalance = s.balances[req.ToAccountId]
	}

	toBalance.AvailableBalance += req.Amount
	toBalance.LastUpdated = now.Unix()

	txRecord := s.createTransactionRecord(txID, req, pb.TransactionStatus_TRANSACTION_STATUS_COMPLETED, now)
	s.transactions[txID] = txRecord

	if req.IdempotencyKey != "" {
		s.idempotencyKeys[req.IdempotencyKey] = txID
	}

	log.Printf("Deposit completed: account %s, amount: %.2f %s, txID: %s",
		req.ToAccountId, req.Amount, req.Currency, txID)

	return &pb.CreateTransactionResponse{
		TransactionId: txID,
		Status:        pb.TransactionStatus_TRANSACTION_STATUS_COMPLETED,
		Message:       "Deposit completed successfully",
		CreatedAt:     now.Unix(),
	}, nil
}

func (s *TransactionServer) processWithdrawal(req *pb.CreateTransactionRequest, txID string, now time.Time) (*pb.CreateTransactionResponse, error) {
	fromBalance, fromExists := s.balances[req.FromAccountId]
	if !fromExists {
		return nil, status.Errorf(codes.NotFound, "account %s not found", req.FromAccountId)
	}

	if fromBalance.AvailableBalance < req.Amount {
		txRecord := s.createTransactionRecord(txID, req, pb.TransactionStatus_TRANSACTION_STATUS_FAILED, now)
		s.transactions[txID] = txRecord
		return &pb.CreateTransactionResponse{
			TransactionId: txID,
			Status:        pb.TransactionStatus_TRANSACTION_STATUS_FAILED,
			Message:       "Insufficient funds for withdrawal",
			CreatedAt:     now.Unix(),
		}, nil
	}

	fromBalance.AvailableBalance -= req.Amount
	fromBalance.LastUpdated = now.Unix()

	txRecord := s.createTransactionRecord(txID, req, pb.TransactionStatus_TRANSACTION_STATUS_COMPLETED, now)
	s.transactions[txID] = txRecord

	if req.IdempotencyKey != "" {
		s.idempotencyKeys[req.IdempotencyKey] = txID
	}

	log.Printf("Withdrawal completed: account %s, amount: %.2f %s, txID: %s",
		req.FromAccountId, req.Amount, req.Currency, txID)

	return &pb.CreateTransactionResponse{
		TransactionId: txID,
		Status:        pb.TransactionStatus_TRANSACTION_STATUS_COMPLETED,
		Message:       "Withdrawal completed successfully",
		CreatedAt:     now.Unix(),
	}, nil
}

func (s *TransactionServer) createTransactionRecord(txID string, req *pb.CreateTransactionRequest, txStatus pb.TransactionStatus, now time.Time) *TransactionRecord {
	return &TransactionRecord{
		TransactionID: txID,
		FromAccountID: req.FromAccountId,
		ToAccountID:   req.ToAccountId,
		Amount:        req.Amount,
		Currency:      req.Currency,
		Type:          req.Type,
		Status:        txStatus,
		Description:   req.Description,
		CreatedAt:     now.Unix(),
	}
}

func (s *TransactionServer) GetBalance(ctx context.Context, req *pb.GetBalanceRequest) (*pb.GetBalanceResponse, error) {
	if req.AccountId == "" {
		return nil, status.Errorf(codes.InvalidArgument, "account_id is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	balance, exists := s.balances[req.AccountId]
	if !exists {
		return nil, status.Errorf(codes.NotFound, "account %s not found", req.AccountId)
	}

	return &pb.GetBalanceResponse{
		AccountId:        req.AccountId,
		AvailableBalance: balance.AvailableBalance,
		PendingBalance:   balance.PendingBalance,
		Currency:         balance.Currency,
		LastUpdated:      balance.LastUpdated,
	}, nil
}

func (s *TransactionServer) GetTransactionHistory(ctx context.Context, req *pb.GetTransactionHistoryRequest) (*pb.GetTransactionHistoryResponse, error) {
	if req.AccountId == "" {
		return nil, status.Errorf(codes.InvalidArgument, "account_id is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	if _, exists := s.balances[req.AccountId]; !exists {
		return nil, status.Errorf(codes.NotFound, "account %s not found", req.AccountId)
	}

	pageSize := int(req.PageSize)
	if pageSize <= 0 {
		pageSize = 20
	}
	if pageSize > 100 {
		pageSize = 100
	}

	var matchingTxns []*pb.Transaction
	for _, tx := range s.transactions {
		if tx.FromAccountID == req.AccountId || tx.ToAccountID == req.AccountId {
			// Apply time filters if provided
			if req.StartTime > 0 && tx.CreatedAt < req.StartTime {
				continue
			}
			if req.EndTime > 0 && tx.CreatedAt > req.EndTime {
				continue
			}

			matchingTxns = append(matchingTxns, &pb.Transaction{
				TransactionId: tx.TransactionID,
				FromAccountId: tx.FromAccountID,
				ToAccountId:   tx.ToAccountID,
				Amount:        tx.Amount,
				Currency:      tx.Currency,
				Type:          tx.Type,
				Status:        tx.Status,
				Description:   tx.Description,
				CreatedAt:     tx.CreatedAt,
			})
		}
	}

	totalCount := len(matchingTxns)

	// Simple pagination
	startIdx := 0
	if req.PageToken != "" {
		for i, tx := range matchingTxns {
			if tx.TransactionId == req.PageToken {
				startIdx = i + 1
				break
			}
		}
	}

	endIdx := startIdx + pageSize
	if endIdx > len(matchingTxns) {
		endIdx = len(matchingTxns)
	}

	paginated := matchingTxns[startIdx:endIdx]

	var nextPageToken string
	if endIdx < len(matchingTxns) {
		nextPageToken = paginated[len(paginated)-1].TransactionId
	}

	return &pb.GetTransactionHistoryResponse{
		Transactions:  paginated,
		NextPageToken: nextPageToken,
		TotalCount:    int32(totalCount),
	}, nil
}

func validateCreateTransactionRequest(req *pb.CreateTransactionRequest) error {
	if req.Amount <= 0 {
		return status.Errorf(codes.InvalidArgument, "amount must be positive")
	}
	if req.Currency == "" {
		return status.Errorf(codes.InvalidArgument, "currency is required")
	}
	if req.Type == pb.TransactionType_TRANSACTION_TYPE_UNSPECIFIED {
		return status.Errorf(codes.InvalidArgument, "transaction type is required")
	}

	switch req.Type {
	case pb.TransactionType_TRANSACTION_TYPE_TRANSFER:
		if req.FromAccountId == "" || req.ToAccountId == "" {
			return status.Errorf(codes.InvalidArgument, "both from_account_id and to_account_id are required for transfers")
		}
		if req.FromAccountId == req.ToAccountId {
			return status.Errorf(codes.InvalidArgument, "from_account_id and to_account_id must be different")
		}
	case pb.TransactionType_TRANSACTION_TYPE_DEPOSIT:
		if req.ToAccountId == "" {
			return status.Errorf(codes.InvalidArgument, "to_account_id is required for deposits")
		}
	case pb.TransactionType_TRANSACTION_TYPE_WITHDRAWAL:
		if req.FromAccountId == "" {
			return status.Errorf(codes.InvalidArgument, "from_account_id is required for withdrawals")
		}
	}

	return nil
}

// Unary interceptor for logging and request tracking
func loggingUnaryInterceptor(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
	start := time.Now()
	log.Printf("[gRPC] Incoming request: %s", info.FullMethod)

	resp, err := handler(ctx, req)

	duration := time.Since(start)
	if err != nil {
		log.Printf("[gRPC] %s completed with error in %v: %v", info.FullMethod, duration, err)
	} else {
		log.Printf("[gRPC] %s completed successfully in %v", info.FullMethod, duration)
	}

	return resp, err
}

// Recovery interceptor to handle panics gracefully
func recoveryUnaryInterceptor(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (resp interface{}, err error) {
	defer func() {
		if r := recover(); r != nil {
			log.Printf("[gRPC] PANIC recovered in %s: %v", info.FullMethod, r)
			err = status.Errorf(codes.Internal, "internal server error")
		}
	}()
	return handler(ctx, req)
}

func chainUnaryInterceptors(interceptors ...grpc.UnaryServerInterceptor) grpc.UnaryServerInterceptor {
	return func(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
		chain := handler
		for i := len(interceptors) - 1; i >= 0; i-- {
			interceptor := interceptors[i]
			next := chain
			chain = func(ctx context.Context, req interface{}) (interface{}, error) {
				return interceptor(ctx, req, info, func(ctx context.Context, req interface{}) (interface{}, error) {
					return next(ctx, req)
				})
			}
		}
		return chain(ctx, req)
	}
}

func main() {
	port := os.Getenv("GRPC_PORT")
	if port == "" {
		port = "50051"
	}

	lis, err := net.Listen("tcp", fmt.Sprintf(":%s", port))
	if err != nil {
		log.Fatalf("Failed to listen on port %s: %v", port, err)
	}

	// Configure gRPC server with keepalive and interceptors
	grpcServer := grpc.NewServer(
		grpc.KeepaliveParams(keepalive.ServerParameters{
			MaxConnectionIdle:     5 * time.Minute,
			MaxConnectionAge:      30 * time.Minute,
			MaxConnectionAgeGrace: 10 * time.Second,
			Time:                  2 * time.Minute,
			Timeout:               20 * time.Second,
		}),
		grpc.KeepaliveEnforcementPolicy(keepalive.EnforcementPolicy{
			MinTime:             30 * time.Second,
			PermitWithoutStream: true,
		}),
		grpc.ChainUnaryInterceptor(
			recoveryUnaryInterceptor,
			loggingUnaryInterceptor,
		),
		grpc.MaxRecvMsgSize(4*1024*1024), // 4MB
		grpc.MaxSendMsgSize(4*1024*1024), // 4MB
	)

	// Register the transaction service
	txServer := NewTransactionServer()
	pb.RegisterTransactionServiceServer(grpcServer, txServer)

	// Register health check service
	healthServer := health.NewServer()
	healthpb.RegisterHealthServer(grpcServer, healthServer)
	healthServer.SetServingStatus("transaction.TransactionService", healthpb.HealthCheckResponse_SERVING)

	// Graceful shutdown
	go func() {
		sigCh := make(chan os.Signal, 1)
		signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)
		sig := <-sigCh
		log.Printf("Received signal %v, initiating graceful shutdown...", sig)
		healthServer.SetServingStatus("transaction.TransactionService", healthpb.HealthCheckResponse_NOT_SERVING)
		grpcServer.GracefulStop()
	}()

	log.Printf("Transaction gRPC server starting on port %s", port)
	if err := grpcServer.Serve(lis); err != nil {
		log.Fatalf("Failed to serve: %v", err)
	}
	log.Println("Server stopped.")
}